233→        e.stopPropagation();
234→        if(bookmarkInFlightRef.current){
235→            return;
236→        }
237→        if(!session){
238→            openAuthModal?.();
239→            return;
240→        }
241→        const wasBookmarked = normalizeInteractionFlag(isBookmarked);
242→        bookmarkInFlightRef.current = true;
243→        setIsBookmarked(!wasBookmarked);
244→        setBookmarkCounts((prevCount) => getNextToggleCount(wasBookmarked, normalizeCount(prevCount)));
245→        let response = null;
246→        try {
247→            response = await mutationBookmark.mutateAsync({ journalId });
248→        } finally {
249→            bookmarkInFlightRef.current = false;
250→        }
251→        
252→        if(timeOutRefBookmark.current){
253→            clearTimeout(timeOutRefBookmark.current);
254→        }
255→        if (response?.message === 'success') {
256→            setBookmarkedMessage('Post was added to your Bookmarks'); 
257→        } else if(response?.message === 'deleted'){
258→            setBookmarkedMessage('Post was removed from your Bookmarks');
259→        }
260→            
261→        timeOutRefBookmark.current = setTimeout(() => {
262→            setBookmarkedMessage('');
263→        }, 1500);
264→
265→    }
