267→
268→    const mutationFollow = useFollowMutation(session);
269→    const handleClickFollow = async (e, followingId, followerId) => {
270→        e.stopPropagation();
271→        if(!session) return openAuthModal();
272→        mutationFollow.mutate({ followingId, followerId });
273→    }
274→    const debounceClickFollow = debounce(handleClickFollow, 100);
275→
276→    const handleBackLocation = (e) => {
277→        e.stopPropagation();
278→        window.history.back();
279→    }
280→
281→    const hanldeClickComments = (e) => {
282→        e.stopPropagation();
283→        if(!session) return openAuthModal();
284→        setShowCommentsContainer(true);
285→    }
286→
