                    }
                }}
            />
        )}

        <AnimatePresence>
            {repostToastMessage && (
                <motion.div
                    className="repost-toast"
                    initial={{ opacity: 0, y: 8 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0, y: 8 }}
                    transition={{ duration: 0.2 }}
                >
                    {repostToastMessage}
                </motion.div>
            )}
        </AnimatePresence>
        </>
    )
}

