    e.preventDefault();
    e.stopPropagation();
    handleClickLike(journalId, receiverId);
},
countLike: (count) => <p style={{padding:'0', margin: '0', fontSize: '0.78rem'}}>{formatCounts(count)}</p>

toolUseResult.oldString:
className: 'like-button',
action: (e, journalId, receiverId) => {
    e.preventDefault();
    e.stopPropagation();
